	int common_change_mem;
	int common_mem;
	int unique_mem;
	int frames_processed;
	int sSize;
	int tSize;
	int maxMove;
	fp alpha;
	int no_frames;
	int frame_rows;
	int frame_cols;
	int frame_elem;
	int frame_mem;
	int endoPoints;
	int endo_mem;
	int epiPoints;
	int epi_mem;
	int allPoints;
	int in_rows;
	int in_cols;
	int in_elem;
	int in_mem;
	int in_pointer_mem;
	int in2_rows;
	int in2_cols;
	int in2_elem;
	int in2_mem;
	int conv_rows;
	int conv_cols;
