void kernel(params_common public, 
            int* endoRow, int* endoCol, int* tEndoRowLoc, int* tEndoColLoc,
            int* epiRow, int* epiCol, int* tEpiRowLoc, int* tEpiColLoc,
            fp* d_frame,
            fp* d_endoT, fp* d_epiT,
            fp* d_in2, fp* d_in2_sqr, fp* d_in_mod, fp* d_in_sqr, fp* d_conv,
            fp* d_in2_pad, fp* d_in2_sub, fp* d_in2_sub2_sqr, fp* d_tMask, fp* d_mask_conv) {

    int point_no = get_global_id(0);
    int is_endo = (point_no < public.endoPoints);

    // Setup pointers based on point_no
    int* d_Row = is_endo ? endoRow : epiRow;
    int* d_Col = is_endo ? endoCol : epiCol;
    int* d_tRowLoc = is_endo ? tEndoRowLoc : tEpiRowLoc;
    int* d_tColLoc = is_endo ? tEndoColLoc : tEpiColLoc;
    fp* d_T = is_endo ? d_endoT : d_epiT;

    // Offsets for per-point arrays
    int in_mod_elem = public.in_mod_rows * public.in_mod_cols;
    int in2_elem = public.in2_rows * public.in2_cols;
    int conv_elem = public.conv_rows * public.conv_cols;
    int in2_pad_elem = public.in2_pad_rows * public.in2_pad_cols;
    int in2_sub_elem = public.in2_sub_rows * public.in2_sub_cols;
    int in2_sub2_sqr_elem = public.in2_sub2_sqr_rows * public.in2_sub2_sqr_cols;
    int tMask_elem = public.tMask_rows * public.tMask_cols;
    int mask_conv_elem = public.mask_conv_rows * public.mask_conv_cols;

    fp* p_d_in2 = d_in2 + point_no * in2_elem;
    fp* p_d_in2_sqr = d_in2_sqr + point_no * in2_elem;
    fp* p_d_in_mod = d_in_mod + point_no * in_mod_elem;
    fp* p_d_in_sqr = d_in_sqr + point_no * in_mod_elem;
    fp* p_d_conv = d_conv + point_no * conv_elem;
    fp* p_d_in2_pad = d_in2_pad + point_no * in2_pad_elem;
    fp* p_d_in2_sub = d_in2_sub + point_no * in2_sub_elem;
    fp* p_d_in2_sub2_sqr = d_in2_sub2_sqr + point_no * in2_sub2_sqr_elem;
    fp* p_d_tMask = d_tMask + point_no * tMask_elem;
    fp* p_d_mask_conv = d_mask_conv + point_no * mask_conv_elem;

    fp* d_in;
    int rot_row, rot_col, in2_rowlow, in2_collow, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
    fp s, temp, temp2, sum, in_final_sum, in_sqr_final_sum, mean, mean_sqr, variance, deviation, denomT;
    int i, j, row, col, ori_row, ori_col, pointer, ori_pointer, pos_ori, position, ei_new;
    int tMask_row, tMask_col, cent, loc_pointer, largest_row, largest_col, offset_row, offset_col;
    fp fin_max_val, temp2_val;
    int fin_max_coo, largest_coordinate;

    int frame_no = public.frame_no; // Assuming frame_no is set in common per iteration or passed differently? 
    // In OpenCL, frame_no might be passed as an extra arg or part of common. 
    // The wrapper likely updates common.frame_no before launching.

    if(frame_no == 0){
        pointer = point_no * public.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no];
        d_tColLoc[pointer] = d_Col[point_no];

        d_in = d_T + point_no * in_mod_elem;

        for(col=0; col<public.in_mod_cols; col++){
            for(row=0; row<public.in_mod_rows; row++){
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public.frame_rows + ori_row;
                d_in[col * public.in_mod_rows + row] = d_frame[ori_pointer];
            }
        }
    }

    if(frame_no != 0){
        in2_rowlow = d_Row[point_no] - public.sSize;
        in2_collow = d_Col[point_no] - public.sSize;

        for(col=0; col<public.in2_cols; col++){
            for(row=0; row<public.in2_rows; row++){
                ori_row = row + in2_rowlow - 1;
                ori_col = col + in2_collow - 1;
                temp = d_frame[ori_col * public.frame_rows + ori_row];
                p_d_in2[col * public.in2_rows + row] = temp;
                p_d_in2_sqr[col * public.in2_rows + row] = temp * temp;
            }
        }

        d_in = d_T + point_no * in_mod_elem;

        for(col=0; col<public.in_mod_cols; col++){
            for(row=0; row<public.in_mod_rows; row++){
                rot_row = (public.in_mod_rows - 1) - row;
                rot_col = (public.in_mod_rows - 1) - col;
                pointer = rot_col * public.in_mod_rows + rot_row;
                temp = d_in[pointer];
                p_d_in_mod[col * public.in_mod_rows + row] = temp;
                p_d_in_sqr[pointer] = temp * temp;
            }
        }

        in_final_sum = 0;
        for(i = 0; i < public.in_mod_elem; i++){
            in_final_sum += d_in[i];
        }

        in_sqr_final_sum = 0;
        for(i = 0; i < public.in_mod_elem; i++){
            in_sqr_final_sum += p_d_in_sqr[i];
        }

        mean = in_final_sum / public.in_mod_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / public.in_mod_elem) - mean_sqr;
        deviation = sqrt(variance);
        denomT = sqrt((fp)(public.in_mod_elem - 1)) * deviation;

        for(col=1; col<=public.conv_cols; col++){
            j = col + public.joffset;
            jp1 = j + 1;
            if(public.in2_cols < jp1) ja1 = jp1 - public.in2_cols; else ja1 = 1;
            if(public.in_mod_cols < j) ja2 = public.in_mod_cols; else ja2 = j;

            for(row=1; row<=public.conv_rows; row++){
                i = row + public.ioffset;
                ip1 = i + 1;
                if(public.in2_rows < ip1) ia1 = ip1 - public.in2_rows; else ia1 = 1;
                if(public.in_mod_rows < i) ia2 = public.in_mod_rows; else ia2 = i;

                s = 0;
                for(ja=ja1; ja<=ja2; ja++){
                    jb = jp1 - ja;
                    for(ia=ia1; ia<=ia2; ia++){
                        ib = ip1 - ia;
                        s += p_d_in_mod[public.in_mod_rows * (ja - 1) + ia - 1] * p_d_in2[public.in2_rows * (jb - 1) + ib - 1];
                    }
                }
                p_d_conv[(col - 1) * public.conv_rows + (row - 1)] = s;
            }
        }

        for(col=0; col<public.in2_pad_cols; col++){
            for(row=0; row<public.in2_pad_rows; row++){
                if(row > (public.in2_pad_add_rows - 1) && row < (public.in2_pad_add_rows + public.in2_rows) &&
                   col > (public.in2_pad_add_cols - 1) && col < (public.in2_pad_add_cols + public.in2_cols)){
                    ori_row = row - public.in2_pad_add_rows;
                    ori_col = col - public.in2_pad_add_cols;
                    p_d_in2_pad[col * public.in2_pad_rows + row] = p_d_in2[ori_col * public.in2_rows + ori_row];
                } else {
                    p_d_in2_pad[col * public.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public.in2_pad_cols; ei_new++){
            pos_ori = ei_new * public.in2_pad_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_pad_rows; position++){
                p_d_in2_pad[position] += sum;
                sum = p_d_in2_pad[position];
            }
        }

        for(col=0; col<public.in2_sub_cols; col++){
            for(row=0; row<public.in2_sub_rows; row++){
                ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel_collow - 1;
                temp = p_d_in2_pad[ori_col * public.in2_pad_rows + ori_row];
                ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
                temp2 = p_d_in2_pad[ori_col * public.in2_pad_rows + ori_row];
                p_d_in2_sub[col * public.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public.in2_sub_rows; ei_new++){
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_sub_elem; position += public.in2_sub_rows){
                p_d_in2_sub[position] += sum;
                sum = p_d_in2_sub[position];
            }
        }

        for(col=0; col<public.in2_sub2_sqr_cols; col++){
            for(row=0; row<public.in2_sub2_sqr_rows; row++){
                ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel_collow - 1;
                temp = p_d_in2_sub[ori_col * public.in2_sub_rows + ori_row];
                ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
                temp2 = p_d_in2_sub[ori_col * public.in2_sub_rows + ori_row];
                temp2 = temp - temp2;
                p_d_in2_sub2_sqr[col * public.in2_sub2_sqr_rows + row] = temp2 * temp2;
                p_d_conv[col * public.in2_sub2_sqr_rows + row] -= temp2 * in_final_sum / public.in_mod_elem;
            }
        }

        // Second pass for sqr
        for(col=0; col<public.in2_pad_cols; col++){
            for(row=0; row<public.in2_pad_rows; row++){
                if(row > (public.in2_pad_add_rows - 1) && row < (public.in2_pad_add_rows + public.in2_rows) &&
                   col > (public.in2_pad_add_cols - 1) && col < (public.in2_pad_add_cols + public.in2_cols)){
                    ori_row = row - public.in2_pad_add_rows;
                    ori_col = col - public.in2_pad_add_cols;
                    p_d_in2_pad[col * public.in2_pad_rows + row] = p_d_in2_sqr[ori_col * public.in2_rows + ori_row];
                } else {
                    p_d_in2_pad[col * public.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public.in2_pad_cols; ei_new++){
            pos_ori = ei_new * public.in2_pad_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_pad_rows; position++){
                p_d_in2_pad[position] += sum;
                sum = p_d_in2_pad[position];
            }
        }

        for(col=0; col<public.in2_sub_cols; col++){
            for(row=0; row<public.in2_sub_rows; row++){
                ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel_collow - 1;
                temp = p_d_in2_pad[ori_col * public.in2_pad_rows + ori_row];
                ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
                temp2 = p_d_in2_pad[ori_col * public.in2_pad_rows + ori_row];
                p_d_in2_sub[col * public.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public.in2_sub_rows; ei_new++){
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori + public.in2_sub_elem; position += public.in2_sub_rows){
                p_d_in2_sub[position] += sum;
                sum = p_d_in2_sub[position];
            }
        }

        for(col=0; col<public.conv_cols; col++){
            for(row=0; row<public.conv_rows; row++){
                ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel_collow - 1;
                temp = p_d_in2_sub[ori_col * public.in2_sub_rows + ori_row];
                ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
                temp2 = p_d_in2_sub[ori_col * public.in2_sub_rows + ori_row];
                temp2 = temp - temp2;
                temp2 = temp2 - (p_d_in2_sub2_sqr[col * public.conv_rows + row] / public.in_mod_elem);
                if(temp2 < 0) temp2 = 0;
                temp2 = sqrt(temp2);
                temp2 = denomT * temp2;
                p_d_conv[col * public.conv_rows + row] /= temp2;
            }
        }

        cent = public.sSize + public.tSize + 1;
        pointer = frame_no - 1 + point_no * public.no_frames;
        tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
        tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

        for(ei_new = 0; ei_new < tMask_elem; ei_new++){
            p_d_tMask[ei_new] = 0;
        }
        p_d_tMask[tMask_col * public.tMask_rows + tMask_row] = 1;

        for(col=1; col<=public.mask_conv_cols; col++){
            j = col + public.mask_conv_joffset;
            jp1 = j + 1;
            if(public.mask_cols < jp1) ja1 = jp1 - public.mask_cols; else ja1 = 1;
            if(public.tMask_cols < j) ja2 = public.tMask_cols; else ja2 = j;

            for(row=1; row<=public.mask_conv_rows; row++){
                i = row + public.mask_conv_ioffset;
                ip1 = i + 1;
                if(public.mask_rows < ip1) ia1 = ip1 - public.mask_rows; else ia1 = 1;
                if(public.tMask_rows < i) ia2 = public.tMask_rows; else ia2 = i;

                s = 0;
                for(ja=ja1; ja<=ja2; ja++){
                    jb = jp1 - ja;
                    for(ia=ia1; ia<=ia2; ia++){
                        ib = ip1 - ia;
                        s += p_d_tMask[public.tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }
                p_d_mask_conv[(col - 1) * public.conv_rows + (row - 1)] = p_d_conv[(col - 1) * public.conv_rows + (row - 1)] * s;
            }
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for(i=0; i<mask_conv_elem; i++){
            if(p_d_mask_conv[i] > fin_max_val){
                fin_max_val = p_d_mask_conv[i];
                fin_max_coo = i;
            }
        }

        largest_row = (fin_max_coo + 1) % public.mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / public.mask_conv_rows;
        if((fin_max_coo + 1) % public.mask_conv_rows == 0){
            largest_row = public.mask_conv_rows - 1;
            largest_col--;
        }
        largest_row++;
        largest_col++;
        offset_row = largest_row - public.in_mod_rows - (public.sSize - public.tSize);
        offset_col = largest_col - public.in_mod_cols - (public.sSize - public.tSize);
        pointer = point_no * public.no_frames + frame_no;
        d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
        d_tColLoc[pointer] = d_Col[point_no] + offset_col;
    }

    if(frame_no != 0 && (frame_no % 10 == 0)){
        loc_pointer = point_no * public.no_frames + frame_no;
        d_Row[point_no] = d_tRowLoc[loc_pointer];
        d_Col[point_no] = d_tColLoc[loc_pointer];

        d_in = d_T + point_no * in_mod_elem;
        for(col=0; col<public.in_mod_cols; col++){
            for(row=0; row<public.in_mod_rows; row++){
                ori_row = d_Row[point_no] - 25 + row - 1;
                ori_col = d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public.frame_rows + ori_row;
                d_in[col * public.in_mod_rows + row] = public.alpha * d_in[col * public.in_mod_rows + row] + (1.00 - public.alpha) * d_frame[ori_pointer];
            }
        }
    }
}
